# Therapeutic Protein Binder Development Pipeline for ERBB3 Kinase

## Executive Summary

This workflow details the computational and experimental pipeline for developing a high-affinity protein binder targeting the ERBB3 (HER3) kinase domain. ERBB3 presents unique challenges as it has impaired kinase activity but remains a critical therapeutic target due to its role in PI3K/AKT signaling and resistance to EGFR/HER2 therapies.

---

## Target Analysis: ERBB3 Kinase Domain

### Structural Characteristics
- **UniProt ID**: P21860
- **Kinase domain**: Residues 711-1013
- **Key feature**: Catalytically impaired (substitutions in key catalytic residues)
- **Available structures**: PDB entries 3LMG, 4OTW, 4RIW (ATP-bound and inhibitor-bound states)

### Target Site Considerations
| Region | Residues | Druggability | Notes |
|--------|----------|--------------|-------|
| ATP-binding cleft | 732-740, 811-820 | High | Conserved across ERBB family |
| Activation loop | 843-869 | Medium | Conformationally flexible |
| C-helix region | 753-767 | High | Unique ERBB3 features |
| Allosteric pocket | 788-802 | Medium | Less conserved |

---

## Phase 1: Initial Binder Scaffold Selection Using AlphaFold2

### 1.1 Scaffold Library Preparation

```python
# scaffold_selection.py
import os
from Bio import PDB
from Bio.PDB import PDBParser, PDBIO, Select
import numpy as np

class ScaffoldLibrary:
    """
    Curated scaffold library for ERBB3 binder development
    """

    SCAFFOLD_CLASSES = {
        'designed_repeat_proteins': {
            'DARPins': {
                'template_pdb': '2QYJ',
                'size_range': (14, 21),  # kDa
                'advantages': ['High stability', 'Modular design', 'No disulfides'],
                'binding_surface': 'concave',
                'typical_affinity': 'pM-nM'
            },
            'Affibodies': {
                'template_pdb': '2B88',
                'size_range': (6, 7),
                'advantages': ['Small size', 'Fast folding', 'Easy production'],
                'binding_surface': 'flat/convex',
                'typical_affinity': 'nM-pM'
            },
            'Anticalins': {
                'template_pdb': '1LNM',
                'size_range': (18, 20),
                'advantages': ['Deep binding pocket', 'Good for small epitopes'],
                'binding_surface': 'pocket',
                'typical_affinity': 'nM'
            },
            'Monobodies': {
                'template_pdb': '3K2M',
                'size_range': (10, 12),
                'advantages': ['Fibronectin-based', 'Two variable loops'],
                'binding_surface': 'loop-mediated',
                'typical_affinity': 'nM'
            }
        },
        'de_novo_scaffolds': {
            'miniproteins': {
                'source': 'RFdiffusion/ProteinMPNN',
                'size_range': (5, 10),
                'advantages': ['Custom topology', 'Optimized interface'],
                'binding_surface': 'designed',
                'typical_affinity': 'pM-nM'
            },
            'helical_bundles': {
                'source': 'Parametric design',
                'size_range': (8, 15),
                'advantages': ['High stability', 'Tunable geometry'],
                'binding_surface': 'helical',
                'typical_affinity': 'nM'
            }
        }
    }

    def __init__(self, output_dir='./scaffolds'):
        self.output_dir = output_dir
        os.makedirs(output_dir, exist_ok=True)

    def evaluate_scaffold_compatibility(self, target_pdb, target_site_residues):
        """
        Evaluate scaffold compatibility with ERBB3 target site
        """
        parser = PDBParser(QUIET=True)
        target_structure = parser.get_structure('ERBB3', target_pdb)

        # Calculate target site properties
        site_analysis = self._analyze_binding_site(
            target_structure, 
            target_site_residues
        )

        compatibility_scores = {}

        for scaffold_class, scaffolds in self.SCAFFOLD_CLASSES.items():
            for scaffold_name, properties in scaffolds.items():
                score = self._calculate_compatibility(
                    site_analysis, 
                    properties
                )
                compatibility_scores[scaffold_name] = {
                    'score': score,
                    'rationale': self._generate_rationale(
                        site_analysis, 
                        properties, 
                        score
                    )
                }

        return compatibility_scores

    def _analyze_binding_site(self, structure, residues):
        """Analyze geometric and chemical properties of binding site"""
        site_atoms = []
        for model in structure:
            for chain in model:
                for residue in chain:
                    if residue.get_id()[1] in residues:
                        for atom in residue:
                            site_atoms.append(atom.get_coord())

        site_atoms = np.array(site_atoms)

        # Calculate site properties
        centroid = np.mean(site_atoms, axis=0)

        # Estimate curvature using PCA
        centered = site_atoms - centroid
        cov_matrix = np.cov(centered.T)
        eigenvalues, eigenvectors = np.linalg.eig(cov_matrix)

        # Sort by eigenvalue
        idx = np.argsort(eigenvalues)[::-1]
        eigenvalues = eigenvalues[idx]

        # Flatness ratio
        flatness = eigenvalues[2] / eigenvalues[0] if eigenvalues[0] > 0 else 0

        return {
            'centroid': centroid,
            'surface_area': len(site_atoms) * 15,  # Approximate
            'flatness': flatness,
            'depth': np.max(np.linalg.norm(centered, axis=1)),
            'n_residues': len(residues)
        }

    def _calculate_compatibility(self, site_analysis, scaffold_properties):
        """Calculate compatibility score between site and scaffold"""
        score = 50  # Base score

        # Surface complementarity
        if scaffold_properties['binding_surface'] == 'flat/convex':
            if site_analysis['flatness'] > 0.3:
                score += 20
        elif scaffold_properties['binding_surface'] == 'concave':
            if site_analysis['flatness'] < 0.3:
                score += 20
        elif scaffold_properties['binding_surface'] == 'pocket':
            if site_analysis['depth'] > 10:
                score += 25

        # Size considerations
        if site_analysis['surface_area'] > 800:  # Large interface
            if scaffold_properties['size_range'][1] > 15:
                score += 15
        else:
            if scaffold_properties['size_range'][0] < 10:
                score += 15

        return min(100, score)

    def _generate_rationale(self, site_analysis, properties, score):
        """Generate design rationale"""
        rationale = []
        if score > 70:
            rationale.append("Excellent geometric complementarity")
        elif score > 50:
            rationale.append("Good potential with optimization")
        else:
            rationale.append("May require significant engineering")
        return "; ".join(rationale)
```

### 1.2 AlphaFold

# Structure-Based Design of a Tight-Binding EGFR Kinase Binder

## Executive Summary

This protocol outlines a comprehensive computational approach to design a protein binder targeting the EGFR (Epidermal Growth Factor Receptor) kinase domain with low-nanomolar affinity (Kd < 10 nM). The design leverages ESMFold for scaffold generation, RFdiffusion/ProteinMPNN for interface optimization, and systematic specificity profiling against related kinases.

---

## 1. Target Analysis and Preparation

### 1.1 EGFR Kinase Domain Characterization

```python
# Target: EGFR Kinase Domain (Homo sapiens)
# UniProt: P00533 (residues 712-979, kinase domain)
# Key structural features for binding:

target_info = {
    "uniprot_id": "P00533",
    "gene_name": "EGFR",
    "kinase_domain": (712, 979),
    "key_binding_sites": {
        "ATP_binding_pocket": {
            "residues": [718, 719, 720, 721, 745, 790, 791, 792, 793, 854, 855],
            "character": "hydrophobic_with_hinge"
        },
        "activation_loop": {
            "residues": range(831, 860),
            "conformations": ["active_DFG-in", "inactive_DFG-out"]
        },
        "allosteric_site": {
            "location": "C-helix/αC region",
            "residues": [761, 762, 763, 764, 765, 766, 767]
        },
        "substrate_binding_groove": {
            "residues": [837, 838, 839, 840, 841],
            "accessibility": "high"
        }
    },
    "druggable_hotspots": [
        "Gly-rich loop (P-loop): 718-725",
        "Hinge region: 790-793", 
        "Gatekeeper: Thr790",
        "DFG motif: 831-833",
        "αC-helix: 761-774"
    ]
}
```

### 1.2 Structure Preparation

```python
import requests
from Bio.PDB import PDBParser, PDBIO, Select
import numpy as np

class EGFRTargetPreparation:
    """Prepare EGFR kinase domain for binder design"""

    def __init__(self):
        self.pdb_ids = {
            "active_WT": "2GS6",      # Active conformation
            "inactive_WT": "2GS7",    # Inactive conformation  
            "T790M_mutant": "3IKA",   # Resistance mutant
            "L858R_mutant": "2ITZ",   # Activating mutant
            "apo_form": "1M14"        # Ligand-free
        }

    def download_and_prepare(self, pdb_id, chain="A"):
        """Download and clean EGFR structure"""
        url = f"https://files.rcsb.org/download/{pdb_id}.pdb"
        response = requests.get(url)

        with open(f"{pdb_id}_raw.pdb", "w") as f:
            f.write(response.text)

        parser = PDBParser(QUIET=True)
        structure = parser.get_structure(pdb_id, f"{pdb_id}_raw.pdb")

        # Extract kinase domain only
        return self._extract_kinase_domain(structure, chain)

    def _extract_kinase_domain(self, structure, chain_id):
        """Extract residues 712-979 (kinase domain)"""
        class KinaseDomainSelect(Select):
            def accept_residue(self, residue):
                return 712 <= residue.id[1] <= 979

        io = PDBIO()
        io.set_structure(structure[0][chain_id])
        io.save("EGFR_kinase_domain.pdb", KinaseDomainSelect())

        return "EGFR_kinase_domain.pdb"

    def identify_binding_interface(self, structure_path):
        """Identify optimal binding interface regions"""
        parser = PDBParser(QUIET=True)
        structure = parser.get_structure("EGFR", structure_path)

        # Calculate surface accessibility
        from Bio.PDB import SASA
        sr = SASA.ShrakeRupley()
        sr.compute(structure, level="R")

        # Identify surface-exposed residues
        surface_residues = []
        for residue in structure.get_residues():
            if hasattr(residue, 'sasa') and residue.sasa > 40:  # Å²
                surface_residues.append(residue)

        return self._prioritize_binding_sites(surface_residues)

    def _prioritize_binding_sites(self, surface_residues):
        """Rank binding sites by druggability"""
        binding_sites = {
            "site_1_substrate_groove": {
                "center": [45.2, 32.1, 28.7],
                "radius": 15.0,
                "priority": 1,
                "rationale": "Natural substrate binding, high specificity potential"
            },
            "site_2_allosteric": {
                "center": [38.5, 45.2, 22.3],
                "radius": 12.0,
                "priority": 2,
                "rationale": "αC-helix region, conformational selectivity"
            },
            "site_3_back_pocket": {
                "center": [52.1, 28.9, 35.4],
                "radius": 10.0,
                "priority": 3,
                "rationale": "Type II inhibitor site, DFG-out selective"
            }
        }
        return binding_sites
```

