## 2. Initial Binder Scaffold Selection Using ESMFold

### 2.1 Scaffold Design Strategy

```python
import torch
import esm
from typing import List, Tuple, Dict
import numpy as np

class ESMFoldScaffoldDesigner:
    """Design and validate binder scaffolds using ESMFold"""

    def __init__(self):
        self.model, self.alphabet = esm.pretrained.esmfold_v1()
        self.model = self.model.eval().cuda()

        # Proven scaffold families for kinase binding
        self.scaffold_templates = {
            "designed_ankyrin_repeat": {
                "base_sequence": "DLGKKLLEAARAGQDDEVRILMANGADVNA",
                "repeat_unit": 33,
                "min_repeats": 3,
                "max_repeats": 6,
                "binding_surface": "concave"
            },
            "monobody_FN3": {
                "base_sequence": self._get_fn3_sequence(),
                "binding_loops": ["BC", "DE", "FG"],
                "loop_lengths": {"BC": (6,12), "DE": (4,8), "FG": (8,14)}
            },
            "designed_helical_repeat": {
                "base_sequence": "EEAKAEEAAKAKEAAKAE",
                "repeat_unit": 18,
                "topology": "antiparallel_helix_bundle"
            },
            "miniprotein": {
                "size_range": (40, 80),
                "topologies": ["3-helix_bundle", "beta-grasp", "cystine_knot"]
            }
        }

    def _get_fn3_sequence(self):
        """FN3 (10th fibronectin type III domain) scaffold"""
        return ("VSDVPRDLEVVAATPTSLLISWDAPAVTVRYYRITYGETGGNSPVQEFTVPG"

# De Novo TIM-Barrel Glucocerebrosidase Design Using RFdiffusion

## Executive Summary

This methodology outlines a comprehensive computational pipeline for designing a synthetic glucocerebrosidase (GBA) replacement enzyme using RFdiffusion-based scaffold generation, ProteinMPNN sequence design, and MD validation. The target is a 250-300 residue TIM-barrel enzyme with catalytic efficiency ≥10⁴ M⁻¹s⁻¹ for glucosylceramide hydrolysis.

---

## 1. TIM-Barrel Scaffold Generation with Active-Site Hallucination

### 1.1 Native GBA Active Site Analysis

First, extract critical geometric parameters from human GBA (PDB: 1OGS, 2NT1):

```python
import numpy as np
from Bio.PDB import PDBParser, Selection
import mdtraj as md

class GBAActiveSiteAnalyzer:
    """Extract geometric constraints from native GBA active site."""

    # Critical catalytic residues in human GBA
    CATALYTIC_RESIDUES = {
        'nucleophile': ('E340', 'GLU'),      # Nucleophilic attack
        'acid_base': ('E235', 'GLU'),         # Proton donor/acceptor
        'positioning': [
            ('D127', 'ASP'),                   # Substrate positioning
            ('W179', 'TRP'),                   # Hydrophobic stacking
            ('W381', 'TRP'),                   # Aromatic platform
            ('F128', 'PHE'),                   # Ceramide binding
            ('Y313', 'TYR'),                   # Hydrogen bonding
            ('N234', 'ASN'),                   # Transition state stabilization
        ]
    }

    def __init__(self, pdb_path):
        self.parser = PDBParser(QUIET=True)
        self.structure = self.parser.get_structure('GBA', pdb_path)

    def extract_active_site_geometry(self):
        """Extract inter-residue distances and angles for active site."""

        constraints = {
            'distances': {},
            'angles': {},
            'dihedrals': {}
        }

        # Critical distance: E235-E340 (catalytic dyad)
        # Native distance: ~5.5 Å (optimal for retaining mechanism)
        e235_cd = self._get_atom_coord('E235', 'CD')
        e340_cd = self._get_atom_coord('E340', 'CD')

        constraints['distances']['catalytic_dyad'] = {
            'atoms': [('E235', 'CD'), ('E340', 'CD')],
            'target': 5.5,
            'tolerance': 0.5,
            'unit': 'angstrom'
        }

        # Nucleophile positioning relative to substrate binding site
        constraints['distances']['nucleophile_to_anomeric'] = {
            'target': 3.2,  # Attack distance
            'tolerance': 0.3
        }

        # Acid/base to glycosidic oxygen
        constraints['distances']['acid_base_to_glycosidic'] = {
            'target': 2.8,  # Proton transfer distance
            'tolerance': 0.3
        }

        return constraints

    def extract_substrate_pocket_volume(self):
        """Calculate binding pocket dimensions for glucosylceramide."""

        pocket_params = {
            'glucose_pocket': {
                'depth': 8.0,      # Å
                'width': 7.0,      # Å
                'volume': 250      # Å³
            },
            'ceramide_channel': {
                'length': 20.0,    # For C18 ceramide
                'width': 5.0,
                'hydrophobicity': 'high'
            }
        }
        return pocket_params

    def _get_atom_coord(self, res_id, atom_name):
        """Get coordinates of specific atom."""
        res_num = int(res_id[1:])
        for model in self.structure:
            for chain in model:
                for residue in chain:
                    if residue.id[1] == res_num:
                        return residue[atom_name].get_coord()
        return None
```

### 1.2 RFdiffusion TIM-Barrel Scaffold Generation

```python
import torch
from rfdiffusion.inference.model_runners import SamplerRunner
from rfdiffusion.inference.utils import parse_pdb

class TIMBarrelDiffusionDesigner:
    """Generate TIM-barrel scaffolds with active site constraints."""

    def __init__(self, model_weights_path):
        self.device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
        self.model = self._load_model(model_weights_path)

    def generate_tim_barrel_config(self):
        """Configure RFdiffusion for TIM-barrel generation."""

        config = {
            # Scaffold parameters
            'scaffold': {
                'topology': 'TIM_barrel',
                'num_strands': 8,           # Classic (β/α)₈ barrel
                'num_helices': 8,
                'strand_length': (5, 8),    # Range for β-strand length
                'helix_length': (10, 20),   # Range for α-helix length
                'total_length': (250, 300), # Target size range
            },

            # Diffusion parameters
            'diffusion': {
                'num_steps': 200,
                'noise_scale': 1.0,
                'final_noise': 0.0,
            },

            # Symmetry constraints for barrel regularity
            'symmetry': {
                'type': 'C8',               # 8-fold pseudo-symmetry
                'strictness': 'soft',       # Allow deviations for active site
            }
        }
        return config

    def create_active_site_hotspot(self, active_site_constraints):
        """Define active site region for hallucination."""

        # Hotspot residues define where catalytic machinery should be placed
        hotspot_config = {
            'contig': 'A1-300',  # Full chain

            # Fixed functional positions (will be designed around these)
            'hotspot_residues': {
                # Approximate positions in TIM barrel C-terminal face
                'nucleophile_region': list(range(180, 190)),
                'acid_base_region': list(range(120, 130)),
                'substrate_binding': list(range(70, 80)) + list(range(200, 210)),
            },

            # Geometric constraints for active site
            'pairwise_constraints': [
                {
                    'res1_range': (180, 190),
                    'res2_range': (120, 130),
                    'distance': (5.0, 6.0),  # Catalytic dyad distance
                    'weight': 10.0
                }
            ]
        }
        return hotspot_config

    def run_scaffold_diffusion(self, config, hotspot_config, num_designs=100):
        """Execute RFdiffusion to generate scaffolds."""

        # RFdiffusion command configuration
        diffusion_args = {
            'inference.output_prefix': 'tim_barrel_gba',
            'inference.num_designs': num_designs,

            # Contig specification for TIM barrel
            'contigmap.contigs': [f"A{config['scaffold']['total_length'][0]}-{config['scaffold']['total_length'][1]}"],

            # Secondary structure guidance
            'potentials.guide_potentials': ['type:secondary_structure'],
            'potentials.ss_weights': {
                'helix': 1.0,
                'strand': 1.0,
                'loop': 0
